from scapy.all import IP, ICMP, sr1

def ping(target):
    '''Custom ICMP ping — analyse TTL for OS detection.'''
    pkt = IP(dst=target) / ICMP()
    response = sr1(pkt, timeout=2, verbose=0)

    if response:
        ttl = response[IP].ttl
        if ttl <= 64:
            os_guess = 'Linux/Unix'
        elif ttl <= 128:
            os_guess = 'Windows'
        else:
            os_guess = 'Network device'
        print(f'{target} is UP — TTL={ttl} → {os_guess}')
    else:
        print(f'{target} is DOWN or blocking ICMP')

